    /// <summary>
    /// Gets rule metadata by RuleId.
    /// </summary>
    /// <param name="id">InspectCode RuleId.</param>
    /// <returns>Rule metadata when found; otherwise <see langword="null"/>.</returns>
    public static InspectCodeRuleMetadata? Get(string? id)
    {
        if (string.IsNullOrWhiteSpace(id))
        {
            return null;
        }

        return MetadataByRuleId.TryGetValue(id, out InspectCodeRuleMetadata? metadata)
            ? metadata
            : null;
    }
}
